import React, { useEffect, useState } from 'react';
import { getTasks, createTask } from '../services/api';

interface Task {
  id: number;
  created_by: number;
  prompt: string;
  status: string;
  created_at: string;
}

const TasksPage: React.FC = () => {
  const [tasks, setTasks] = useState<Task[]>([]);
  const [prompt, setPrompt] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    fetchTasks();
  }, []);

  const fetchTasks = async () => {
    try {
      const data = await getTasks();
      setTasks(data);
    } catch (err) {
      setError('Failed to load tasks');
    }
  };

  const handleCreateTask = async () => {
    if (!prompt.trim()) {
      setError('Please enter a prompt');
      return;
    }
    setLoading(true);
    setError('');
    try {
      await createTask({ created_by: 1, prompt });
      setPrompt('');
      fetchTasks();
    } catch (err) {
      setError('Failed to create task');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ padding: '2rem', maxWidth: '800px', margin: '0 auto' }}>
      <h1 style={{ marginBottom: '1.5rem' }}>Tasks</h1>

      {/* Create Task Form */}
      <div style={{
        background: '#f9f9f9',
        padding: '1.5rem',
        borderRadius: '8px',
        marginBottom: '2rem',
        border: '1px solid #eee'
      }}>
        <h2 style={{ marginBottom: '1rem', fontSize: '1.1rem' }}>Create New Task</h2>
        <textarea
          value={prompt}
          onChange={(e) => setPrompt(e.target.value)}
          placeholder="Enter a prompt for AI models to answer..."
          style={{
            width: '100%',
            minHeight: '100px',
            padding: '0.75rem',
            borderRadius: '6px',
            border: '1px solid #ddd',
            fontSize: '0.95rem',
            marginBottom: '1rem',
            boxSizing: 'border-box',
            resize: 'vertical'
          }}
        />
        {error && (
          <p style={{ color: 'red', marginBottom: '0.5rem' }}>{error}</p>
        )}
        <button
          onClick={handleCreateTask}
          disabled={loading}
          style={{
            background: '#2563eb',
            color: 'white',
            border: 'none',
            padding: '0.6rem 1.4rem',
            borderRadius: '6px',
            cursor: loading ? 'not-allowed' : 'pointer',
            fontSize: '0.95rem',
            opacity: loading ? 0.7 : 1
          }}
        >
          {loading ? 'Creating...' : 'Create Task'}
        </button>
      </div>

      {/* Tasks List */}
      <h2 style={{ marginBottom: '1rem', fontSize: '1.1rem' }}>All Tasks</h2>
      {tasks.length === 0 ? (
        <p style={{ color: '#888' }}>No tasks yet. Create one above.</p>
      ) : (
        tasks.map((task) => (
          <div key={task.id} style={{
            background: 'white',
            border: '1px solid #eee',
            borderRadius: '8px',
            padding: '1.25rem',
            marginBottom: '1rem',
            boxShadow: '0 1px 3px rgba(0,0,0,0.05)'
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
              <span style={{ fontWeight: 600 }}>Task #{task.id}</span>
              <span style={{
                background: task.status === 'completed' ? '#dcfce7' : '#fef9c3',
                color: task.status === 'completed' ? '#166534' : '#854d0e',
                padding: '0.2rem 0.6rem',
                borderRadius: '999px',
                fontSize: '0.8rem',
                fontWeight: 500
              }}>
                {task.status}
              </span>
            </div>
            <p style={{ color: '#444', marginBottom: '0.5rem' }}>{task.prompt}</p>
            <p style={{ color: '#999', fontSize: '0.8rem' }}>
              Created: {new Date(task.created_at).toLocaleString()}
            </p>
          </div>
        ))
      )}
    </div>
  );
};

export default TasksPage;
